
'use client';

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { FileText, PlusCircle, Calendar, Clock, Users, AlertTriangle, X } from "lucide-react";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger, DialogClose } from '@/components/ui/dialog';
import { Separator } from '@/components/ui/separator';

const tripReportsData = [
  { id: 'TR101', date: '2024-05-20', duration: '42 mins', students: 24, issues: 1, issueDetails: 'Heavy traffic near Main St caused a 15-minute delay.' },
  { id: 'TR102', date: '2024-05-21', duration: '40 mins', students: 25, issues: 0, issueDetails: null },
  { id: 'TR103', date: '2024-05-22', duration: '39 mins', students: 25, issues: 0, issueDetails: null },
];

type TripReport = typeof tripReportsData[0];

export default function TripReportsPage() {
  const [isDetailsOpen, setIsDetailsOpen] = useState(false);
  const [selectedReport, setSelectedReport] = useState<TripReport | null>(null);

  const handleViewDetails = (report: TripReport) => {
    setSelectedReport(report);
    setIsDetailsOpen(true);
  };

  return (
    <div className="space-y-8">
       <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
            <div>
                <h1 className="text-3xl font-bold font-headline">Trip Reports</h1>
                <p className="text-muted-foreground">Review your past trip summaries.</p>
            </div>
            <Button>
                <PlusCircle className="mr-2 h-4 w-4" /> Start New Trip Report
            </Button>
        </div>

      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2"><FileText className="h-5 w-5 text-primary" /> Past Reports</CardTitle>
          <CardDescription>A summary of your completed trips.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Report ID</TableHead>
                  <TableHead>Date</TableHead>
                  <TableHead className="hidden md:table-cell">Duration</TableHead>
                  <TableHead>Students</TableHead>
                  <TableHead>Issues</TableHead>
                   <TableHead><span className="sr-only">Actions</span></TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {tripReportsData.map((report) => (
                  <TableRow key={report.id}>
                    <TableCell className="font-medium">{report.id}</TableCell>
                    <TableCell>{report.date}</TableCell>
                    <TableCell className="hidden md:table-cell">{report.duration}</TableCell>
                    <TableCell>{report.students}</TableCell>
                     <TableCell>
                       <Badge variant={report.issues > 0 ? 'destructive' : 'secondary'}>{report.issues}</Badge>
                    </TableCell>
                    <TableCell>
                        <Button variant="outline" size="sm" onClick={() => handleViewDetails(report)}>View Details</Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      <Dialog open={isDetailsOpen} onOpenChange={setIsDetailsOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Trip Report Details</DialogTitle>
            <DialogDescription>
              A detailed summary of trip report {selectedReport?.id}.
            </DialogDescription>
          </DialogHeader>
          {selectedReport && (
            <div className="space-y-4 py-4 text-sm">
                <div className="flex items-center">
                    <Calendar className="mr-3 h-4 w-4 text-muted-foreground"/>
                    <span className="font-medium">Date:</span>
                    <span className="ml-2 text-muted-foreground">{selectedReport.date}</span>
                </div>
                <div className="flex items-center">
                    <Clock className="mr-3 h-4 w-4 text-muted-foreground"/>
                    <span className="font-medium">Duration:</span>
                    <span className="ml-2 text-muted-foreground">{selectedReport.duration}</span>
                </div>
                <div className="flex items-center">
                    <Users className="mr-3 h-4 w-4 text-muted-foreground"/>
                    <span className="font-medium">Students Transported:</span>
                    <span className="ml-2 text-muted-foreground">{selectedReport.students}</span>
                </div>
                <Separator />
                <div className="flex items-start">
                     <AlertTriangle className={`mr-3 h-4 w-4 ${selectedReport.issues > 0 ? 'text-destructive' : 'text-green-500'}`}/>
                    <div>
                        <span className="font-medium">Issues Logged:</span>
                        {selectedReport.issues > 0 ? (
                           <p className="text-muted-foreground mt-1">{selectedReport.issueDetails}</p>
                        ) : (
                           <p className="text-muted-foreground mt-1">No issues were logged for this trip.</p>
                        )}
                    </div>
                </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}
